mapper.select:
SELECT id, member_id, gym_id, tag, color, created_at
  FROM crm_member_tags
 WHERE member_id = #{memberId}
   AND gym_id    = #{gymId}
 ORDER BY created_at ASC

mapper.delete:
DELETE FROM crm_member_tags
 WHERE id     = #{tagId}
   AND gym_id = #{gymId}

mapper.select:
SELECT trainer_id
  FROM crm_member_assignments
 WHERE member_id = #{memberId}
   AND gym_id    = #{gymId}
 LIMIT 1
